-- 4.2 Управление обязательного контроля и отчётности
WITH ins AS (
  INSERT INTO t_p61016064_digital_innovation_i.dept_functions (project_id, dept_name, title, category, source_section_code)
  SELECT 1, 'Департамент финансового мониторинга (ДФМ)', v.title, v.category, '4.2'
  FROM (VALUES
    ('Осуществление контроля соблюдения работниками ГО Банка и филиалов Банка ПВК по ПОД/ФТ и программ их осуществления в рамках вопросов, относящихся к функционалу Управления обязательного контроля и отчётности','control'),
    ('Осуществление консультирования работников Банка по вопросам, находящимся в компетенции Управления обязательного контроля и отчётности','communication'),
    ('Взаимодействие с Банком России, Уполномоченным органом в рамках подготовки и предоставления сведений на их письменные запросы в рамках наделённого функционала','communication'),
    ('Разработка внутренних нормативных документов Банка, в том числе ПВК по ПОД/ФТ и программ их осуществления, в части, касающейся деятельности Управления обязательного контроля и отчётности','methodology'),
    ('Инициирование доработки специализированных программных комплексов Банка в связи с изменениями законодательства Российской Федерации в сфере ПОД/ФТ, в части, касающейся деятельности Управления обязательного контроля и отчётности','operational'),
    ('Осуществление анализа выявленных типовых нарушений законодательства Российской Федерации, а также внутрибанковских политик и процедур в филиалах Банка, разработка мероприятий по их устранению и осуществление контроля за их устранением по функционалу Управления обязательного контроля и отчётности','analytical')
  ) AS v(title, category)
  RETURNING id, source_section_code
)
INSERT INTO t_p61016064_digital_innovation_i.function_org_units (function_id, org_unit_id, role, source_ref)
SELECT ins.id, u.id, 'owner', 'polozhenie'
FROM ins JOIN t_p61016064_digital_innovation_i.org_units u
  ON u.project_id = 1 AND u.code = '4.2' AND u.is_archived = false;